#!/usr/bin/env node

/**
* Test file to verify accessor array support in nanstdevwd
*/

'use strict';

// MODULES //

var toAccessorArray = require( '@stdlib/array/base/to-accessor-array' );
var nanstdevwd = require( './../lib' );

// TESTS //

console.log( 'Testing accessor array support...\n' );

// Test 1: Basic accessor array
var x1 = toAccessorArray( [ 1.0, -2.0, NaN, 2.0 ] );
var v1 = nanstdevwd( x1.length, 1, x1, 1 );
console.log( 'Test 1 - Basic accessor array:' );
console.log( '  Input: [ 1.0, -2.0, NaN, 2.0 ]' );
console.log( '  Result:', v1 );
console.log( '  Expected: ~2.0817' );
console.log( '  Pass:', Math.abs( v1 - 2.0817 ) < 0.01 );
console.log();

// Test 2: Accessor array with stride
var x2 = toAccessorArray( [ 1.0, 99.0, 2.0, 99.0, NaN, 99.0, 4.0 ] );
var v2 = nanstdevwd( 4, 1, x2, 2 );
console.log( 'Test 2 - Accessor array with stride:' );
console.log( '  Input: [ 1.0, 99.0, 2.0, 99.0, NaN, 99.0, 4.0 ] with stride=2' );
console.log( '  Result:', v2 );
console.log( '  Expected: ~1.528' );
console.log( '  Pass:', Math.abs( v2 - 1.528 ) < 0.01 );
console.log();

// Test 3: ndarray API with accessor array
var x3 = toAccessorArray( [ 99.0, 1.0, 99.0, -2.0, 99.0, NaN, 99.0, 2.0 ] );
var v3 = nanstdevwd.ndarray( 4, 1, x3, 2, 1 );
console.log( 'Test 3 - ndarray API with accessor array and offset:' );
console.log( '  Input: [ 99.0, 1.0, 99.0, -2.0, 99.0, NaN, 99.0, 2.0 ] with stride=2, offset=1' );
console.log( '  Result:', v3 );
console.log( '  Expected: ~2.0817' );
console.log( '  Pass:', Math.abs( v3 - 2.0817 ) < 0.01 );
console.log();

// Test 4: Negative stride
var x4 = toAccessorArray( [ 4.0, 99.0, NaN, 99.0, 2.0, 99.0, 1.0 ] );
var v4 = nanstdevwd( 4, 1, x4, -2 );
console.log( 'Test 4 - Accessor array with negative stride:' );
console.log( '  Input: [ 4.0, 99.0, NaN, 99.0, 2.0, 99.0, 1.0 ] with stride=-2' );
console.log( '  Result:', v4 );
console.log( '  Expected: ~1.528' );
console.log( '  Pass:', Math.abs( v4 - 1.528 ) < 0.01 );
console.log();

console.log( 'All accessor array tests completed successfully!' );

